import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

record SteadyState(
    long p99Ms,          // p99 response time under chaos
    double errorRatePct, // error rate during chaos
    String cbState       // circuit breaker state: CLOSED, OPEN, HALF_OPEN
) {
    // Hypothesis thresholds during chaos:
    static final long MAX_P99_MS = 2000;      // 2s (lenient — chaos is running)
    static final double MAX_ERROR_PCT = 5.0;  // 5% (CB should catch most failures)
    static final String EXPECTED_CB = "OPEN"; // CB should be open under chaos

    boolean meetsHypothesis() {
        return p99Ms <= MAX_P99_MS
            && errorRatePct <= MAX_ERROR_PCT
            && EXPECTED_CB.equals(cbState);
    }
}

@Service
class SteadyStateMonitor {
    // In production: read from Micrometer/Prometheus
    // In tests: inject simulated values
    private long simulatedP99 = 200;
    private double simulatedErrorRate = 0.1;
    private String simulatedCbState = "CLOSED";

    public void simulate(long p99, double errRate, String cbState) {
        simulatedP99 = p99; simulatedErrorRate = errRate; simulatedCbState = cbState;
    }

    public SteadyState captureSnapshot() {
        return new SteadyState(simulatedP99, simulatedErrorRate, simulatedCbState);
    }

    public boolean isInSteadyState(SteadyState snapshot) {
        // Pre-chaos steady state: p99 < 500ms, error < 1%, CB CLOSED
        return snapshot.p99Ms() < 500
            && snapshot.errorRatePct() < 1.0
            && "CLOSED".equals(snapshot.cbState());
    }
}

@SpringBootTest
class SteadyStateTest {
    @Autowired SteadyStateMonitor monitor;

    @Test void normalState_isSteadyState() {
        monitor.simulate(200, 0.2, "CLOSED");
        assertTrue(monitor.isInSteadyState(monitor.captureSnapshot()));
    }
    @Test void chaosHypothesis_evaluated() {
        SteadyState chaos = new SteadyState(1500, 3.5, "OPEN");
        assertTrue(chaos.meetsHypothesis()); // 1500<2000, 3.5<5.0, OPEN=OPEN
    }
    @Test void hypothesisBreached_detected() {
        SteadyState chaos = new SteadyState(3000, 3.5, "OPEN");
        assertFalse(chaos.meetsHypothesis()); // 3000 > 2000: p99 too high
    }
}

