import io.github.resilience4j.circuitbreaker.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;

@Service
class ChaosResilienceVerifier {
    private final Map<String, AtomicInteger> fallbackCounters = new HashMap<>();
    private final Map<String, CircuitBreaker.State> cbStates = new HashMap<>();

    // Simulate chaos: record CB transitions and fallback invocations
    public void simulateChaos(String serviceName, int callsWithFailures) {
        fallbackCounters.put(serviceName, new AtomicInteger(callsWithFailures));
        // After enough failures: circuit breaker OPENS:
        cbStates.put(serviceName,
            callsWithFailures >= 5 ? CircuitBreaker.State.OPEN : CircuitBreaker.State.CLOSED);
    }

    public boolean verifyCircuitBreakerOpened(String serviceName) {
        CircuitBreaker.State state = cbStates.getOrDefault(serviceName, CircuitBreaker.State.CLOSED);
        return state != CircuitBreaker.State.CLOSED;
    }

    public boolean verifyFallbackActivated(String serviceName) {
        return fallbackCounters.getOrDefault(serviceName, new AtomicInteger(0)).get() > 0;
    }

    public boolean verifyRecovery(String serviceName) {
        // After chaos stops: CB transitions to HALF_OPEN, then CLOSED
        cbStates.put(serviceName, CircuitBreaker.State.CLOSED);
        fallbackCounters.getOrDefault(serviceName, new AtomicInteger(0)).set(0);
        return cbStates.get(serviceName) == CircuitBreaker.State.CLOSED;
    }
}

@SpringBootTest
class ResilienceVerificationTest {
    @Autowired ChaosResilienceVerifier verifier;

    @Test void chaos_causesCBToOpen() {
        verifier.simulateChaos("hdfc-service", 10); // 10 failures
        assertTrue(verifier.verifyCircuitBreakerOpened("hdfc-service"));
    }
    @Test void chaos_activatesFallback() {
        verifier.simulateChaos("visa-service", 7);
        assertTrue(verifier.verifyFallbackActivated("visa-service"));
    }
    @Test void afterChaos_recoveryToClosedState() {
        verifier.simulateChaos("kyc-service", 10);
        assertTrue(verifier.verifyRecovery("kyc-service")); // CB back to CLOSED
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

record ChaosMetrics(long p99Ms, double errorRatePct, boolean cbOpened, int fallbackCount) {}
record ChaosHypothesis(long maxP99Ms, double maxErrorPct, boolean requireCbOpen) {
    boolean isMet(ChaosMetrics m) {
        return m.p99Ms() <= maxP99Ms
            && m.errorRatePct() <= maxErrorPct
            && (!requireCbOpen || m.cbOpened());
    }
}

@Service
class ChaosExperimentPipeline {
    private ChaosMetrics baseline;
    private ChaosMetrics chaosMetrics;

    // Step 1: capture normal operation metrics
    public void captureBaseline() {
        baseline = new ChaosMetrics(200, 0.2, false, 0);
    }

    // Step 2+3: inject chaos and run load (simulated)
    public ChaosMetrics runChaosExperiment(boolean cbOpens) {
        chaosMetrics = new ChaosMetrics(
            cbOpens ? 450 : 3200,  // if CB opens: p99 is fast (fallback fast)
            cbOpens ? 2.0 : 15.0,  // if CB opens: low error rate (fallback works)
            cbOpens,
            cbOpens ? 25 : 0       // fallback count
        );
        return chaosMetrics;
    }

    // Step 5: validate
    public boolean validate(ChaosHypothesis hypothesis, ChaosMetrics observed) {
        return hypothesis.isMet(observed);
    }

    public String report(ChaosHypothesis h, ChaosMetrics m) {
        return String.format(
            "[CHAOS RESULT] p99=%dms (max=%d) err=%.1f%% (max=%.1f%%) CB=%s fallback=%d → %s",
            m.p99Ms(), h.maxP99Ms(), m.errorRatePct(), h.maxErrorPct(),
            m.cbOpened(), m.fallbackCount(),
            h.isMet(m) ? "HYPOTHESIS MET ✓" : "HYPOTHESIS VIOLATED ✗");
    }
}

@SpringBootTest
class ChaosExperimentTest {
    @Autowired ChaosExperimentPipeline pipeline;

    @Test void cbOpens_hypothesisMet() {
        pipeline.captureBaseline();
        ChaosMetrics observed = pipeline.runChaosExperiment(true); // CB opens
        ChaosHypothesis hypothesis = new ChaosHypothesis(2000, 5.0, true);
        assertTrue(pipeline.validate(hypothesis, observed));
        System.out.println(pipeline.report(hypothesis, observed));
    }
    @Test void cbStaysClosed_hypothesisViolated() {
        pipeline.captureBaseline();
        ChaosMetrics observed = pipeline.runChaosExperiment(false); // CB stays closed!
        ChaosHypothesis hypothesis = new ChaosHypothesis(2000, 5.0, true);
        assertFalse(pipeline.validate(hypothesis, observed));
        System.out.println(pipeline.report(hypothesis, observed));
    }
}

