@Service
class DatabaseChaosSimulator {
    private boolean chaosEnabled = false;
    void enable() { chaosEnabled = true; }
    void disable() { chaosEnabled = false; }

    public List<String> findPayments(String merchantId) {
        if (chaosEnabled) throw new TransientDataAccessException("DB connection lost") {};
        return List.of("PAY-001", "PAY-002");
    }
}

@Service
class ResiliencePaymentService {
    private final DatabaseChaosSimulator db;
    private final AtomicInteger fallbackCount = new AtomicInteger(0);

    ResiliencePaymentService(DatabaseChaosSimulator d) { db = d; }

    @CircuitBreaker(name = "payment-db", fallbackMethod = "paymentsFallback")
    public List<String> getPayments(String merchantId) {
        return db.findPayments(merchantId);
    }

    public List<String> paymentsFallback(String merchantId, Exception ex) {
        fallbackCount.incrementAndGet();
        // Return stale cached data (graceful degradation):
        return List.of("CACHED-PAY-001");
    }

    int getFallbackCount() { return fallbackCount.get(); }
}

@SpringBootTest
class DatabaseChaosTest {
    @Autowired DatabaseChaosSimulator db;
    @Autowired ResiliencePaymentService svc;

    @BeforeEach void reset() { db.disable(); }

    @Test void dbChaos_fallbackReturnsCachedData() {
        db.enable();
        int before = svc.getFallbackCount();
        // Run requests — DB throws → fallback activates:
        List<String> result = svc.getPayments("MRC-001");
        assertTrue(result.contains("CACHED-PAY-001"), "Fallback should return cached data");
        assertTrue(svc.getFallbackCount() > before, "Fallback should have been called");
    }
    @Test void dbRecovery_normalDataReturned() {
        db.disable(); // chaos stopped
        List<String> result = svc.getPayments("MRC-001");
        assertTrue(result.contains("PAY-001"), "Should return real data after recovery");
    }
}

