import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

enum ChaosType { LATENCY, EXCEPTION, KILL_APP, MEMORY, NETWORK_PARTITION }
enum BlastRadius { POD_LEVEL, SERVICE_LEVEL, REGION_LEVEL }

record GameDayExperiment(
    String name,
    String hypothesis,         // 'When X, then Y'
    ChaosType chaosType,
    BlastRadius blastRadius,   // how much of the system is affected
    String rollbackProcedure,  // how to stop the chaos immediately
    int maxDurationSeconds     // how long to run chaos before stopping
) {
    boolean isValid() {
        return name != null && !name.isBlank()
            && hypothesis != null && hypothesis.contains("When")
            && rollbackProcedure != null
            && maxDurationSeconds > 0 && maxDurationSeconds <= 3600; // max 1 hour
    }
}

@Service
class GameDayRunner {
    public List<GameDayExperiment> getRazorpayExperiments() {
        return List.of(
            new GameDayExperiment(
                "HDFC Latency Storm",
                "When HDFC gateway has 3s latency, circuit breaker opens and VISA fallback activates within 10 calls",
                ChaosType.LATENCY, BlastRadius.POD_LEVEL,
                "POST /actuator/chaosmonkey/assaults {latencyActive:false}",
                300),
            new GameDayExperiment(
                "Payment DB Exception Flood",
                "When payment DB throws TransientDataAccessException, cached payment list is returned and no money is double-charged",
                ChaosType.EXCEPTION, BlastRadius.SERVICE_LEVEL,
                "chaos.monkey.enabled=false in actuator",
                120),
            new GameDayExperiment(
                "Kafka Consumer Lag",
                "When Kafka consumer lag reaches 10000, settlement service shows degraded but payment creation still works",
                ChaosType.NETWORK_PARTITION, BlastRadius.SERVICE_LEVEL,
                "Remove network partition rule (iptables -D)",
                180)
        );
    }
    public boolean validateHypothesis(GameDayExperiment exp, boolean cbOpened, boolean fallbackWorked) {
        if (exp.chaosType() == ChaosType.LATENCY) return cbOpened && fallbackWorked;
        if (exp.chaosType() == ChaosType.EXCEPTION) return fallbackWorked;
        return fallbackWorked;
    }
}

@SpringBootTest
class GameDayTest {
    @Autowired GameDayRunner runner;
    @Test void experiments_areValid() {
        runner.getRazorpayExperiments().forEach(exp ->
            assertTrue(exp.isValid(), "Experiment '" + exp.name() + "' should be valid"));
    }
    @Test void latencyHypothesis_requiresBoth() {
        var latencyExp = runner.getRazorpayExperiments().get(0);
        assertTrue(runner.validateHypothesis(latencyExp, true, true));
        assertFalse(runner.validateHypothesis(latencyExp, false, true)); // CB not opened = fail
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;

record ChaosExp(String name,String hypothesis){}
record ChaosObservation(boolean cbOpened,int fallbacks,long p99Ms,double errorRatePct){}
record ChaosOutcome(String name,boolean hypothesisMet,String summary){}

@Service
class RzpChaosRunner {
    private final List<ChaosOutcome> results=new ArrayList<>();

    public ChaosOutcome run(ChaosExp exp, ChaosObservation obs, long maxP99, double maxErr){
        boolean met=obs.p99Ms()<=maxP99&&obs.errorRatePct()<=maxErr&&obs.fallbacks()>0;
        ChaosOutcome outcome=new ChaosOutcome(exp.name(),met,
            String.format("%s: p99=%dms err=%.1f%% fallback=%d CB=%s → %s",
                exp.name(),obs.p99Ms(),obs.errorRatePct(),obs.fallbacks(),
                obs.cbOpened(),met?"PASS":"FAIL"));
        results.add(outcome); return outcome;
    }
    List<ChaosOutcome> getResults(){return Collections.unmodifiableList(results);}
    long passCount(){return results.stream().filter(ChaosOutcome::hypothesisMet).count();}
    void reset(){results.clear();}
}

@SpringBootTest
class RzpChaosFullTest {
    @Autowired RzpChaosRunner runner;
    @BeforeEach void reset(){runner.reset();}

    @Test void hdfcLatency_experiment(){
        ChaosExp exp=new ChaosExp("HDFC Latency","When HDFC has 3s latency, fallback activates and p99 < 1000ms");
        // CB opens + fast fallback keeps p99 low:
        ChaosObservation obs=new ChaosObservation(true,15,450,2.5);
        ChaosOutcome outcome=runner.run(exp,obs,1000,5.0);
        assertTrue(outcome.hypothesisMet());
        assertTrue(outcome.summary().contains("PASS"));
    }
    @Test void dbFailure_experiment(){
        ChaosExp exp=new ChaosExp("DB Failure","When DB throws, cached data returned and error rate < 5%");
        ChaosObservation obs=new ChaosObservation(false,20,300,3.0);
        ChaosOutcome outcome=runner.run(exp,obs,2000,5.0);
        assertTrue(outcome.hypothesisMet()); // fallback works, p99 fine
    }
    @Test void notificationDown_hypothesisFails(){
        // Notification service down: payments OK but no fallback activated (not resilient enough)
        ChaosExp exp=new ChaosExp("Notification Down","When notification svc fails, payments still complete with fallback");
        ChaosObservation obs=new ChaosObservation(false,0,200,0.5); // 0 fallbacks = broken!
        ChaosOutcome outcome=runner.run(exp,obs,1000,2.0);
        assertFalse(outcome.hypothesisMet()); // fallback=0: notification has no fallback!
        assertTrue(outcome.summary().contains("FAIL"));
    }
}

import org.springframework.stereotype.*;
