record DiscoveredGap(
    String experiment, String observation, String rootCause, String fix
){}

@Service
class ChaosGapTracker {
    private final List<DiscoveredGap> gaps=new ArrayList<>();
    private final Map<String,Boolean> fixesApplied=new HashMap<>();

    void recordGap(DiscoveredGap g){gaps.add(g);}
    void markFixed(String experiment){fixesApplied.put(experiment,true);}
    boolean isFixed(String experiment){return fixesApplied.getOrDefault(experiment,false);}
    List<DiscoveredGap> getOpenGaps(){
        return gaps.stream().filter(g->!fixesApplied.containsKey(g.experiment())).toList();
    }

    // Re-run chaos after fix — verify improvement:
    boolean verifyChaosRegression(String experiment,boolean chaosNowPasses){
        if(!isFixed(experiment)) return false; // fix not yet applied
        return chaosNowPasses; // if chaos now passes: fix worked
    }
}

@SpringBootTest
class ChaosRegressionTest {
    @Autowired ChaosGapTracker tracker;

    @BeforeEach void reset(){ tracker.getOpenGaps().forEach(g->{});
        // Can't clear directly — use specific experiment names per test
    }

    @Test void gap_discovered_from_chaos(){
        DiscoveredGap gap=new DiscoveredGap(
            "HDFC-Latency-Exp-1",
            "CB did not open under 3s latency",
            "slowCallDurationThreshold was set to 10s, too lenient",
            "Set slowCallDurationThreshold=1s in resilience4j config"
        );
        tracker.recordGap(gap);
        assertFalse(tracker.getOpenGaps().isEmpty());
