import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;

@Service
class SynthHdfcSvc {
    private boolean chaos=false;
    private final AtomicInteger fbCount=new AtomicInteger(0);
    void enableChaos(){chaos=true;} void disableChaos(){chaos=false;}
    int getFbCount(){return fbCount.get();} void reset(){chaos=false;fbCount.set(0);}

    @CircuitBreaker(name="synth-hdfc",fallbackMethod="fb")
    public String charge(String m,long a){
        if(chaos) throw new RuntimeException("chaos");
        return "OK:"+m;
    }
    public String fb(String m,long a,Exception e){fbCount.incrementAndGet();return "FB:"+m;}
}

record SynthSteadyState(long p99,double errRate,boolean chaosActive){}
record SynthHypothesis(long maxP99,double maxErr,boolean requireFallback){
    boolean isMet(SynthSteadyState s,int fallbacks){
        return s.p99()<=maxP99&&s.errRate()<=maxErr&&(!requireFallback||fallbacks>0);
    }
}

@Service
class SynthGameDayRunner {
    List<String> experiments(){return List.of("HDFC-Latency","DB-Exception","Notif-Down");}
    boolean runHypothesis(SynthHypothesis h,SynthSteadyState s,int fb){return h.isMet(s,fb);}
}

@SpringBootTest
class M25T5SynthesisTest {
    @Autowired SynthHdfcSvc svc;
    @Autowired SynthGameDayRunner gameDay;
    @BeforeEach void reset(){svc.reset();}

    @Test void chaos_activates_fallback(){
        svc.enableChaos();
        String result=svc.charge("M1",100L);
        assertTrue(result.startsWith("FB:"));
        assertEquals(1,svc.getFbCount());
    }
    @Test void hypothesis_met_when_fallback_works(){
        svc.enableChaos();
        svc.charge("M2",100L);
        SynthHypothesis h=new SynthHypothesis(2000,5.0,true);
        SynthSteadyState s=new SynthSteadyState(300,2.0,true);
        assertTrue(gameDay.runHypothesis(h,s,svc.getFbCount()));
    }
    @Test void hypothesis_fails_without_fallback(){
        SynthHypothesis h=new SynthHypothesis(2000,5.0,true);
        SynthSteadyState s=new SynthSteadyState(300,2.0,true);
        assertFalse(gameDay.runHypothesis(h,s,0)); // 0 fallbacks → fails
    }
    @Test void after_chaos_stops_normal_behavior(){
        svc.disableChaos();
        String result=svc.charge("M3",100L);
        assertTrue(result.startsWith("OK:"));
    }
}
